import { useState, useEffect } from 'react';
import io from 'socket.io-client';
import dynamic from 'next/dynamic';

const QRCode = dynamic(() => import('qrcode'), { ssr: false });

let socket = null;

const SOCKET_URL = process.env.NEXT_PUBLIC_SOCKET_URL || '';
const API_URL = process.env.NEXT_PUBLIC_API_URL || '';

export default function AdminPage() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [token, setToken] = useState('');
  const [gameState, setGameState] = useState(null);
  const [players, setPlayers] = useState([]);
  const [activeTab, setActiveTab] = useState('lobby');
  const [showSettings, setShowSettings] = useState(false);
  const [settings, setSettings] = useState({
    questionsCount: 20,
    questionTime: 15,
    pointsPerQuestion: 100,
    pauseBetweenQuestions: 5,
    gameMode: 'classic',
    timeBonus: true,
    shuffleQuestions: true,
  });
  const [notification, setNotification] = useState('');

  useEffect(() => {
    const savedToken = localStorage.getItem('admin_token');
    if (savedToken) {
      setToken(savedToken);
      setLoggedIn(true);
      connectSocket(savedToken);
    }
  }, []);

  const connectSocket = (authToken) => {
    if (socket) socket.disconnect();

    const socketUrl = SOCKET_URL || window.location.origin;
    socket = io(socketUrl, {
      path: SOCKET_URL ? '/socket.io' : undefined,
      auth: { token: authToken }
    });

    socket.on('connect', () => {
      console.log('Admin connected');
    });

    socket.on('admin:update', (state) => {
      setGameState(state);
    });

    socket.on('players:update', (playerList) => {
      setPlayers(playerList);
    });

    socket.on('game:timer', ({ remainingMs }) => {
      // Timer handled by state
    });

    socket.on('game:pauseTimer', ({ remainingMs }) => {
      // Pause timer handled by state
    });

    socket.on('disconnect', () => {
      console.log('Admin disconnected');
    });
  };

  const handleLogin = async () => {
    try {
      const apiBase = API_URL || '';
      const res = await fetch(`${apiBase}/api/admin/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const data = await res.json();
      if (data.token) {
        setToken(data.token);
        setLoggedIn(true);
        localStorage.setItem('admin_token', data.token);
        connectSocket(data.token);
      } else {
        showNotification(data.error || 'Грешка при вход');
      }
    } catch (err) {
      showNotification('Грешка при вход');
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('admin_token');
    setLoggedIn(false);
    setToken('');
    if (socket) socket.disconnect();
  };

  const apiRequest = async (endpoint, options = {}) => {
    const apiBase = API_URL || '';
    const res = await fetch(`${apiBase}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
        ...options.headers,
      },
    });
    const data = await res.json();
    if (!res.ok) throw new Error(data.error);
    return data;
  };

  const createGame = async () => {
    try {
      await apiRequest('/api/admin/game/create', { method: 'POST' });
      showNotification('Играта е създадена!');
    } catch (err) {
      showNotification(err.message);
    }
  };

  const startGame = async () => {
    try {
      await apiRequest('/api/admin/game/start', { method: 'POST' });
      showNotification('Играта започна!');
    } catch (err) {
      showNotification(err.message);
    }
  };

  const nextQuestion = async () => {
    try {
      await apiRequest('/api/admin/game/next', { method: 'POST' });
    } catch (err) {
      showNotification(err.message);
    }
  };

  const endGame = async () => {
    if (!confirm('Край на играта?')) return;
    try {
      await apiRequest('/api/admin/game/end', { method: 'POST' });
      showNotification('Играта приключи!');
    } catch (err) {
      showNotification(err.message);
    }
  };

  const saveSettings = async () => {
    try {
      await apiRequest('/api/admin/game/settings', {
        method: 'POST',
        body: JSON.stringify(settings),
      });
      setShowSettings(false);
      showNotification('Настройките са запазени!');
    } catch (err) {
      showNotification(err.message);
    }
  };

  const kickPlayer = async (playerToken) => {
    try {
      await apiRequest('/api/admin/game/kick', {
        method: 'POST',
        body: JSON.stringify({ playerToken }),
      });
      showNotification('Играчът е изгонен!');
    } catch (err) {
      showNotification(err.message);
    }
  };

  const showNotification = (msg) => {
    setNotification(msg);
    setTimeout(() => setNotification(''), 3000);
  };

  if (!loggedIn) {
    return (
      <div style={styles.container}>
        <div style={styles.loginCard}>
          <h1 style={styles.logo}>PGITECH</h1>
          <p style={styles.subtitle}>Админ панел</p>
          <input
            type="text"
            placeholder="Потребител"
            value={username}
            onChange={(e) => setUsername(e.target.value)}
            style={styles.input}
          />
          <input
            type="password"
            placeholder="Парола"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            style={styles.input}
            onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
          />
          <button onClick={handleLogin} style={styles.primaryBtn}>
            Вход
          </button>
        </div>
      </div>
    );
  }

  const state = gameState?.state || 'lobby';
  const isLobby = state === 'lobby' || state === 'ready';
  const isPlaying = state === 'question' || state === 'pause' || state === 'reveal';

  return (
    <div style={styles.container}>
      {notification && <div style={styles.notification}>{notification}</div>}

      <header style={styles.header}>
        <span style={styles.brand}>PGITECH</span>
        <div style={styles.headerRight}>
          {gameState?.gameCode && (
            <span style={styles.gameCode}>{gameState.gameCode}</span>
          )}
          <span style={styles.playerCount}>
            {gameState?.playersCount || 0} играчи
          </span>
          <button onClick={() => setShowSettings(true)} style={styles.headerBtn}>
            ⚙️
          </button>
          <button onClick={handleLogout} style={styles.headerBtn}>
            Изход
          </button>
        </div>
      </header>

      <nav style={styles.tabs}>
        <button
          style={{ ...styles.tab, ...(activeTab === 'lobby' ? styles.activeTab : {}) }}
          onClick={() => setActiveTab('lobby')}
        >
          Лоби
        </button>
        <button
          style={{ ...styles.tab, ...(activeTab === 'game' ? styles.activeTab : {}) }}
          onClick={() => setActiveTab('game')}
        >
          Игра
        </button>
        <button
          style={{ ...styles.tab, ...(activeTab === 'players' ? styles.activeTab : {}) }}
          onClick={() => setActiveTab('players')}
        >
          Играчи
        </button>
      </nav>

      <main style={styles.main}>
        {activeTab === 'lobby' && (
          <div>
            {isLobby ? (
              <div style={styles.lobbyCard}>
                <h2>Играта е готова!</h2>
                {gameState?.gameCode && (
                  <>
                    <div style={styles.qrSection}>
                      <QRCode value={`${window.location.origin}?code=${gameState.gameCode}`} size={150} />
                    </div>
                    <p style={styles.gameCodeBig}>{gameState.gameCode}</p>
                  </>
                )}
                <div style={styles.stats}>
                  <div style={styles.stat}>
                    <div style={styles.statValue}>{gameState?.playersCount || 0}</div>
                    <div style={styles.statLabel}>Играчи</div>
                  </div>
                  <div style={styles.stat}>
                    <div style={styles.statValue}>{settings.questionsCount}</div>
                    <div style={styles.statLabel}>Въпроси</div>
                  </div>
                  <div style={styles.stat}>
                    <div style={styles.statValue}>{settings.questionTime}с</div>
                    <div style={styles.statLabel}>Време</div>
                  </div>
                </div>
                {state === 'lobby' && (
                  <button onClick={createGame} style={styles.successBtn}>
                    Създай игра
                  </button>
                )}
                {state === 'ready' && (
                  <button onClick={startGame} style={styles.successBtn}>
                    🚀 Старт на играта!
                  </button>
                )}
              </div>
            ) : (
              <div style={styles.waitingCard}>
                <h2>Готов ли си?</h2>
                <p>Създай игра и покани играчи!</p>
                <button onClick={createGame} style={styles.primaryBtn}>
                  Създай игра
                </button>
              </div>
            )}
          </div>
        )}

        {activeTab === 'game' && (
          <div>
            <div style={styles.gameGrid}>
              <div style={styles.card}>
                <h3>⏱️ Таймер</h3>
                <div style={styles.timerBig}>
                  {gameState?.state === 'question'
                    ? Math.max(0, Math.ceil((gameState.questionEndsAt - Date.now()) / 1000))
                    : gameState?.state === 'pause'
                    ? Math.max(0, Math.ceil((gameState.pauseEndsAt - Date.now()) / 1000))
                    : '15'}
                </div>
              </div>

              <div style={styles.card}>
                <h3>📊 Прогрес</h3>
                <div style={styles.stats}>
                  <div style={styles.stat}>
                    <div style={styles.statValue}>
                      {(gameState?.currentQuestionIndex >= 0 ? gameState.currentQuestionIndex + 1 : 0)}/{gameState?.totalQuestions || 0}
                    </div>
                    <div style={styles.statLabel}>Въпрос</div>
                  </div>
                  <div style={styles.stat}>
                    <div style={styles.statValue}>{gameState?.answeredPlayers || 0}</div>
                    <div style={styles.statLabel}>Отговорили</div>
                  </div>
                </div>
              </div>
            </div>

            <div style={styles.card}>
              <h3>📈 Разпределение</h3>
              <div style={styles.answerBars}>
                {['Лява е Човек', 'Дясна е Човек', 'Двете са Човек', 'Двете са ИИ'].map((label, i) => (
                  <div key={i} style={styles.answerBar}>
                    <span style={styles.answerLabel}>{label}</span>
                    <div style={styles.answerTrack}>
                      <div
                        style={{
                          ...styles.answerFill,
                          width: `${gameState?.answerCounts?.[i]
                            ? (gameState.answerCounts[i] / (gameState.answeredPlayers || 1)) * 100
                            : 0}%`,
                          background: ['#ef4444', '#3b82f6', '#eab308', '#22c55e'][i],
                        }}
                      />
                    </div>
                    <span style={styles.answerCount}>{gameState?.answerCounts?.[i] || 0}</span>
                  </div>
                ))}
              </div>
            </div>

            <div style={styles.controls}>
              <button onClick={nextQuestion} style={styles.primaryBtn}>
                ⏭️ {state === 'pause' ? 'Покажи отговора' : 'Следващ'}
              </button>
              <button onClick={endGame} style={styles.dangerBtn}>
                ⏹️ Край
              </button>
            </div>
          </div>
        )}

        {activeTab === 'players' && (
          <div style={styles.card}>
            <h3>👥 Играчи ({players.length})</h3>
            <table style={styles.table}>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Име</th>
                  <th>Точки</th>
                  <th>Действия</th>
                </tr>
              </thead>
              <tbody>
                {players.map((player, i) => (
                  <tr key={player.token}>
                    <td>{i + 1}</td>
                    <td>{player.name}</td>
                    <td>{player.score}</td>
                    <td>
                      <button
                        onClick={() => kickPlayer(player.token)}
                        style={styles.kickBtn}
                      >
                        Изгони
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>

      {showSettings && (
        <div style={styles.modal}>
          <div style={styles.modalContent}>
            <h2>⚙️ Настройки</h2>
            <div style={styles.settingsGrid}>
              <div style={styles.settingItem}>
                <label>Брой въпроси</label>
                <input
                  type="number"
                  value={settings.questionsCount}
                  onChange={(e) => setSettings({ ...settings, questionsCount: parseInt(e.target.value) })}
                  style={styles.input}
                />
              </div>
              <div style={styles.settingItem}>
                <label>Време за въпрос (сек)</label>
                <input
                  type="number"
                  value={settings.questionTime}
                  onChange={(e) => setSettings({ ...settings, questionTime: parseInt(e.target.value) })}
                  style={styles.input}
                />
              </div>
              <div style={styles.settingItem}>
                <label>Точки за въпрос</label>
                <input
                  type="number"
                  value={settings.pointsPerQuestion}
                  onChange={(e) => setSettings({ ...settings, pointsPerQuestion: parseInt(e.target.value) })}
                  style={styles.input}
                />
              </div>
              <div style={styles.settingItem}>
                <label>Пауза между въпроси</label>
                <input
                  type="number"
                  value={settings.pauseBetweenQuestions}
                  onChange={(e) => setSettings({ ...settings, pauseBetweenQuestions: parseInt(e.target.value) })}
                  style={styles.input}
                />
              </div>
            </div>
            <div style={styles.modalBtns}>
              <button onClick={() => setShowSettings(false)} style={styles.secondaryBtn}>
                Отказ
              </button>
              <button onClick={saveSettings} style={styles.primaryBtn}>
                Запази
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

